POST /webhook/product-launch
Body: { product_name, product_price, product_type, creator_name, creator_niche, launch_date, subscriber_count }
O1: Predictive Revenue Optimisation ($18K-$20K/year)

parameters.jsCode:
// ══════════════════════════════════════════════
// CreatorIQ — Generate 5-Email Launch Sequence
// AI-powered email campaign for product launches
// In production: replace content with Claude API calls
// Value: 10 hours saved per launch, $18K-$20K/year
// ══════════════════════════════════════════════

const b = $input.first().json.body || $input.first().json;
const productName    = b.product_name    || 'Your New Course';
const productPrice   = b.product_price   || 97;
const productType    = b.product_type    || 'course';
const creatorName    = b.creator_name    || 'Creator';
const creatorNiche   = b.creator_niche   || 'lifestyle';
const launchDate     = b.launch_date     || new Date().toISOString().split('T')[0];
const subscribers    = b.subscriber_count || 5000;
const earlyBirdPrice = Math.round(productPrice * 0.75);
const earlyBirdEnd   = new Date(new Date(launchDate).getTime() + 3*24*60*60*1000).toISOString().split('T')[0];

const emailSequence = [
  {
    send_day:    0,
    email_num:   1,
    type:        'ANNOUNCEMENT',
    subject:     `🎉 It's HERE! ${productName} is now live`,
    preview:     `Early bird pricing ends in 72 hours — save $${productPrice - earlyBirdPrice}`,
    purpose:     'Launch announcement + early bird offer',
    key_message: `After months of work, ${productName} is finally here. For the next 72 hours, founding members get it for just $${earlyBirdPrice} (normally $${productPrice}).`,
    cta:         `Get Early Bird Access — $${earlyBirdPrice}`,
    urgency:     'HIGH'
  },
  {
    send_day:    2,
    email_num:   2,
    type:        'SOCIAL_PROOF',
    subject:     `💬 What early students are already saying about ${productName}`,
    preview:     '72 hours in — the results are already coming in',
    purpose:     'Build trust with early testimonials',
    key_message: `We've had ${Math.round(subscribers * 0.02)} founding members join in 48 hours. Here's what they're saying...`,
    cta:         `Join ${Math.round(subscribers * 0.02)} founding members`,
    urgency:     'MEDIUM'
  },
  {
    send_day:    6,
    email_num:   3,
    type:        'VALUE_DEEPDIVE',
    subject:     `What's actually inside ${productName} (full breakdown)`,
    preview:     'Module by module — exactly what you get',
    purpose:     'Overcome objections with full value breakdown',
    key_message: `Let me show you exactly what you get inside ${productName} and why this is the most comprehensive ${productType} on ${creatorNiche}.`,
    cta:         `Get Instant Access — $${productPrice}`,
    urgency:     'LOW'
  },
  {
    send_day:    13,
    email_num:   4,
    type:        'TRANSFORMATION',
    subject:     `Week 1 results from ${productName} students 🙌`,
    preview:     'Real people, real results in just 7 days',
    purpose:     'Show transformation stories to re-engage fence-sitters',
    key_message: `One week in. The results from ${productName} students are blowing my mind. Let me share a few stories with you.`,
    cta:         `Start Your Transformation`,
    urgency:     'MEDIUM'
  },
  {
    send_day:    29,
    email_num:   5,
    type:        'LAST_CHANCE',
    subject:     `⏰ Final 24 hours — ${productName} closes tonight`,
    preview:     'After midnight, the doors close. No exceptions.',
    purpose:     'Final urgency push to convert last-minute buyers',
    key_message: `This is your last reminder. Tonight at midnight, ${productName} closes its doors. If you've been on the fence, now is the time.`,
    cta:         `Grab Your Spot Before Midnight`,
    urgency:     'CRITICAL'
  }
];

return emailSequence.map(email => ({
  json: {
    ...email,
    product_name:      productName,
    product_price:     productPrice,
    early_bird_price:  earlyBirdPrice,
    early_bird_end:    earlyBirdEnd,
    creator_name:      creatorName,
    creator_niche:     creatorNiche,
    launch_date:       launchDate,
    subscriber_count:  subscribers,
    campaign_id:       `LAUNCH-${new Date().getTime()}`,
    scheduled_for:     new Date(new Date(launchDate).getTime() + email.send_day*24*60*60*1000).toISOString().split('T')[0],
    workflow:          'O1 — Product Launch Email Sequence'
  }
}));
